// ── Notion: HTTP cru + paginação (this.helpers vem do runtime do Code node) ──
const NOTION_TOKEN = $env.NOTION_TOKEN;
const NOTION_VERSION = $env.NOTION_VERSION || '2022-06-28';
const HELPERS = this.helpers;
function notionHeaders() {
  return { Authorization: `Bearer ${NOTION_TOKEN}`, 'Notion-Version': NOTION_VERSION, 'Content-Type': 'application/json' };
}
async function notionQueryAll(databaseId, filter, sorts) {
  let results = [];
  let cursor;
  do {
    const body = { page_size: 100 };
    if (filter) body.filter = filter;
    if (sorts) body.sorts = sorts;
    if (cursor) body.start_cursor = cursor;
    const resp = await HELPERS.httpRequest({
      method: 'POST',
      url: `https://api.notion.com/v1/databases/${databaseId}/query`,
      headers: notionHeaders(),
      body,
      json: true,
    });
    results = results.concat(resp.results || []);
    cursor = resp.has_more ? resp.next_cursor : null;
  } while (cursor);
  return results;
}
async function notionCreatePage(databaseId, properties) {
  return HELPERS.httpRequest({
    method: 'POST',
    url: 'https://api.notion.com/v1/pages',
    headers: notionHeaders(),
    body: { parent: { database_id: databaseId }, properties },
    json: true,
  });
}
async function notionUpdatePage(pageId, properties) {
  return HELPERS.httpRequest({
    method: 'PATCH',
    url: `https://api.notion.com/v1/pages/${pageId}`,
    headers: notionHeaders(),
    body: { properties },
    json: true,
  });
}

// ── Glue: Metas (todas — status importa pro filtro em JS) + Lançamentos com meta ──
const [metasRows, lancamentosComMeta] = await Promise.all([
  notionQueryAll($env.NOTION_DB_METAS),
  notionQueryAll($env.NOTION_DB_LANCAMENTOS, { and: [
    { property: 'Status', select: { equals: 'confirmado' } },
    { property: 'Meta', rich_text: { is_not_empty: true } },
  ] }),
]);
return [{ json: { metasRows, lancamentosComMeta } }];

// Lógica pura da gestão de metas — progresso derivado dos Lançamentos, mensagem
// e teclados inline do /metas, parse de /novameta e dos callbacks gm*.
// Implementa gstack/plans/gerenciar-metas.md.
//
// Progresso é SEMPRE derivado dos Lançamentos (fonte da verdade); a coluna C de
// Metas (valor_acumulado) é só cache reescrito no glue, nunca lida como fonte.
// CRUD distinto da associação lançamento→meta da categorização (prefixo meta|).

const TEMPLATE_NOVAMETA =
  "Para criar uma meta, envie:\n" +
  "/novameta <nome> | <orçamento> | <prazo>\n" +
  "Ex.: /novameta Cama Nova | 1800 | 2026-12";

function formatarReal(n) {
  const [int, dec] = Number(n).toFixed(2).split(".");
  return `R$ ${int.replace(/\B(?=(\d{3})+(?!\d))/g, ".")},${dec}`;
}

function assertCb(botao) {
  if (Buffer.byteLength(botao.callback_data, "utf-8") > 64) {
    throw new Error(`callback_data excede 64 bytes: ${botao.callback_data}`);
  }
  return botao;
}

/**
 * Progresso de cada meta ATIVA, derivado dos Lançamentos.
 * acumulado = Σ |valor| dos lançamentos com status=confirmado e id_meta==nome
 * (match exato após trim dos dois lados — espaço de borda casa, case-sensitive).
 * @param {Array<{nome,orcamento_total,prazo,status}>} metas aba Metas (A:F)
 * @param {Array<{valor,status,id_meta}>} lancamentos aba Lançamentos (A:J)
 * @returns {Array<{nome,orcamento,acumulado,pct:(number|null),prazo}>}
 */
function calcularProgresso(metas, lancamentos) {
  return (metas || [])
    .filter((m) => String(m.status || "").trim().toLowerCase() === "ativa")
    .map((m) => {
      const nome = String(m.nome || "").trim();
      const orcamento = Number(m.orcamento_total) || 0;
      const acumulado = (lancamentos || [])
        .filter(
          (l) =>
            String(l.status || "").trim().toLowerCase() === "confirmado" &&
            String(l.id_meta || "").trim() === nome
        )
        .reduce((s, l) => s + Math.abs(Number(l.valor) || 0), 0);
      const pct = orcamento > 0 ? Math.round((acumulado / orcamento) * 100) : null;
      return { nome, orcamento, acumulado, pct, prazo: String(m.prazo || "").trim() };
    });
}

/** Mensagem do /metas: lista cada meta ativa; vazio → convite a criar. */
function montarMensagemMetas(progresso) {
  if (!progresso || progresso.length === 0) {
    return `🎯 Você ainda não tem metas ativas.\n\n${TEMPLATE_NOVAMETA}`;
  }
  const linhas = progresso.map((p) => {
    const acum = formatarReal(p.acumulado);
    if (p.pct === null) return `🎯 ${p.nome}\n   ${acum} acumulado · até ${p.prazo}`;
    return `🎯 ${p.nome}\n   ${acum} / ${formatarReal(p.orcamento)} (${p.pct}%) · até ${p.prazo}`;
  });
  return `Suas metas ativas:\n\n${linhas.join("\n\n")}`;
}

/** Teclado do /metas: 🏁 Encerrar por meta (gmenc|) + linha final ➕ Nova meta (gmnova|). */
function montarTecladoMetas(progresso) {
  const linhas = (progresso || []).map((p) => [
    assertCb({ text: `🏁 Encerrar ${p.nome}`, callback_data: `gmenc|${p.nome}` }),
  ]);
  linhas.push([assertCb({ text: "➕ Nova meta", callback_data: "gmnova|" })]);
  return { inline_keyboard: linhas };
}

/** Teclado de confirmação de encerramento (2 toques): ✅ Confirmar → gmok|<nome>. */
function montarTecladoConfirmarEncerrar(nome) {
  return {
    inline_keyboard: [
      [assertCb({ text: "✅ Confirmar encerramento", callback_data: `gmok|${nome}` })],
    ],
  };
}

/** Valor em formato BR: ponto milhar, vírgula decimal. Inválido → null. */
function parsearValorBR(bruto) {
  const s = String(bruto || "")
    .replace(/r\$/i, "")
    .replace(/\s/g, "")
    .replace(/\./g, "")
    .replace(",", ".");
  if (s === "") return null;
  const n = Number(s);
  return Number.isFinite(n) ? n : null;
}

/** Prazo aceito: AAAA-MM ou AAAA-MM-DD (mês 1–12, dia 1–31). */
function prazoValido(prazo) {
  const m = /^(\d{4})-(\d{2})(?:-(\d{2}))?$/.exec(String(prazo || "").trim());
  if (!m) return false;
  const mes = Number(m[2]);
  if (mes < 1 || mes > 12) return false;
  if (m[3]) {
    const dia = Number(m[3]);
    if (dia < 1 || dia > 31) return false;
  }
  return true;
}

/** Nome de meta: trim, não vazio, sem '|', curto o bastante p/ caber no callback_data. */
function validarNomeMeta(nome) {
  const n = String(nome || "").trim();
  if (n === "") return { ok: false, erro: "Nome da meta não pode ser vazio." };
  if (n.includes("|")) return { ok: false, erro: "Nome da meta não pode conter '|'." };
  if (Buffer.byteLength(`gmok|${n}`, "utf-8") > 64) {
    return { ok: false, erro: "Nome da meta longo demais (máx ~59 caracteres)." };
  }
  return { ok: true, nome: n };
}

/**
 * Interpreta `/novameta <nome> | <orçamento> | <prazo>` (stateless).
 * @returns {{ok:true, meta:{nome,orcamento,prazo}} | {ok:false, erro:string}}
 */
function parsearNovaMeta(texto) {
  const corpo = String(texto || "").replace(/^\/novameta(@\S+)?/i, "").trim();
  const partes = corpo.split("|").map((p) => p.trim());
  const erroFmt = (msg) => ({ ok: false, erro: `${msg}\n\n${TEMPLATE_NOVAMETA}` });
  if (partes.length !== 3 || partes.some((p) => p === "")) {
    return erroFmt("Formato inválido — preencha nome, orçamento e prazo separados por '|'.");
  }
  const [nomeBruto, orcamentoBruto, prazo] = partes;
  const vn = validarNomeMeta(nomeBruto);
  if (!vn.ok) return erroFmt(vn.erro);
  const orcamento = parsearValorBR(orcamentoBruto);
  if (orcamento === null || orcamento <= 0) return erroFmt("Orçamento inválido — use um número, ex.: 1800.");
  if (!prazoValido(prazo)) return erroFmt("Prazo inválido — use AAAA-MM, ex.: 2026-12.");
  return { ok: true, meta: { nome: vn.nome, orcamento, prazo } };
}

/** Já existe meta ATIVA com esse nome? (homônimo de encerrada é permitido). */
function nomeJaExisteAtiva(nome, metas) {
  const alvo = String(nome || "").trim();
  return (metas || []).some(
    (m) =>
      String(m.status || "").trim().toLowerCase() === "ativa" &&
      String(m.nome || "").trim() === alvo
  );
}

/** Parse dos callbacks gm*. gmnova| → nova; gmenc|<nome>; gmok|<nome>. Inválido → null. */
function parsearCallbackMetaGestao(data) {
  const s = String(data || "");
  if (s === "gmnova|") return { acao: "nova" };
  const m = /^(gmenc|gmok)\|(.+)$/.exec(s);
  if (!m) return null;
  return { acao: m[1] === "gmenc" ? "encerrar-confirmar" : "encerrar-ok", nome: m[2] };
}

// Mapeamento puro entre o shape "flat" usado pela lógica de negócio reaproveitada de
// workflows/src/*.js (parser-cartao, parser-conta, dashboard, rateio, ...) e o formato
// de properties da API do Notion (POST /v1/pages, POST /v1/databases/{id}/query).
// Sem I/O — só transformação de dados. Concatenado nos Code nodes do n8n junto com
// os módulos puros originais (ver scripts/gerar-workflow-*-notion.js).
// Implementa a Fase A de gstack (schema em workflows-harumi/README... ver plano da branch).

/** "DD/MM/YYYY" ou "YYYY-MM-DD" → "YYYY-MM-DD" (Notion exige ISO); inválido/vazio → null. */
function paraIso(data) {
  if (data === null || data === undefined || data === "") return null;
  const s = String(data).trim();
  let m;
  if ((m = /^(\d{4})-(\d{2})-(\d{2})/.exec(s))) return `${m[1]}-${m[2]}-${m[3]}`;
  if ((m = /^(\d{2})\/(\d{2})\/(\d{4})$/.exec(s))) return `${m[3]}-${m[2]}-${m[1]}`;
  return null;
}

/**
 * Texto plano de uma property title/rich_text do Notion. As demais funções de
 * leitura (paraObjeto*) devolvem "YYYY-MM-DD" para datas — mesDe()/normalizarData()
 * em workflows/src/*.js já aceitam esse formato ISO nativamente, então nenhuma
 * conversão adicional é necessária na leitura (só na escrita, via paraIso).
 */
function textoDe(prop) {
  if (!prop) return "";
  const arr = prop.title || prop.rich_text || [];
  return arr.map((t) => t.plain_text || "").join("");
}

const richText = (s) => (s ? [{ text: { content: String(s).slice(0, 2000) } }] : []);
const selectOrNull = (s) => (s ? { select: { name: String(s) } } : { select: null });
const dateOrNull = (isoOuBr) => {
  const iso = paraIso(isoOuBr);
  return iso ? { date: { start: iso } } : { date: null };
};

// ─── Lançamentos ────────────────────────────────────────────────────────────

/** Page do Notion (results[i] de um query em Lançamentos) → objeto flat esperado pelos parsers/dashboard. */
function paraObjetoLancamento(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    data_competencia: (p["Data Competência"] && p["Data Competência"].date && p["Data Competência"].date.start) || "",
    data_original: (p["Data Original"] && p["Data Original"].date && p["Data Original"].date.start) || "",
    descricao: textoDe(p["Descrição"]),
    titulo: "",
    valor: (p["Valor"] && p["Valor"].number) || 0,
    categoria: (p["Categoria"] && p["Categoria"].select && p["Categoria"].select.name) || "",
    tipo: (p["Tipo"] && p["Tipo"].select && p["Tipo"].select.name) || "",
    origem: (p["Origem"] && p["Origem"].select && p["Origem"].select.name) || "",
    status: (p["Status"] && p["Status"].select && p["Status"].select.name) || "",
    id_meta: textoDe(p["Meta"]),
  };
}

/** Objeto flat (saída do parser-cartao/parser-conta) → properties para criar a page no Notion. */
function propsDeLancamento(l) {
  return {
    "Descrição": { title: richText(l.descricao || l.titulo || "(sem descrição)") },
    "Valor": { number: Number(l.valor) || 0 },
    "Categoria": selectOrNull(l.categoria),
    "Tipo": selectOrNull(l.tipo),
    "Origem": selectOrNull(l.origem),
    "Status": selectOrNull(l.status),
    "Meta": { rich_text: richText(l.id_meta) },
    "Data Competência": dateOrNull(l.data_competencia),
    "Data Original": dateOrNull(l.data_original),
  };
}

/** Update parcial (PATCH) de um Lançamento: só Categoria+Meta — não toca nas demais properties. */
function propsCategoriaEMeta(categoria, idMeta) {
  return { "Categoria": selectOrNull(categoria), "Meta": { rich_text: richText(idMeta) } };
}

// ─── Dicionário ─────────────────────────────────────────────────────────────

function paraObjetoDicionario(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    descricao_original: textoDe(p["Descrição Original"]),
    categoria_mapeada: (p["Categoria Mapeada"] && p["Categoria Mapeada"].select && p["Categoria Mapeada"].select.name) || "",
    origem: (p["Origem"] && p["Origem"].select && p["Origem"].select.name) || "",
    criado_em: (p["Criado Em"] && p["Criado Em"].date && p["Criado Em"].date.start) || "",
  };
}

/** Dicionário lido vira { chave, categoria } (contrato de parser-cartao.categorizar / parser-conta). */
function paraDicionarioChaveCategoria(objetosDicionario) {
  return objetosDicionario.map((d) => ({ chave: d.descricao_original, categoria: d.categoria_mapeada }));
}

function propsDeDicionario(d) {
  // Criado Em nunca fica vazio: cai no dia de hoje se d.criado_em não vier preenchido.
  const criadoEm = paraIso(d.criado_em) || new Date().toISOString().slice(0, 10);
  return {
    "Descrição Original": { title: richText(d.descricao_original || "(vazio)") },
    "Categoria Mapeada": selectOrNull(d.categoria_mapeada),
    "Origem": selectOrNull(d.origem),
    "Criado Em": { date: { start: criadoEm } },
  };
}

// ─── Categorias ─────────────────────────────────────────────────────────────

function paraObjetoCategoria(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    nome: textoDe(p["Nome"]),
    tipo: (p["Tipo"] && p["Tipo"].select && p["Tipo"].select.name) || "",
    ativo: !!(p["Ativo"] && p["Ativo"].checkbox),
  };
}

function propsDeCategoria(c) {
  return {
    "Nome": { title: richText(c.nome || "(sem nome)") },
    "Tipo": selectOrNull(c.tipo),
    "Ativo": { checkbox: !!c.ativo },
  };
}

// ─── Metas ──────────────────────────────────────────────────────────────────
// Prazo fica RICH_TEXT (não Date): metas.js aceita "AAAA-MM" (sem dia) além de
// "AAAA-MM-DD" — um Date do Notion exige dia, então forçaria uma escolha arbitrária
// (dia 1? último dia?) que a lógica pura nunca precisou fazer. Texto preserva o
// valor exatamente como o usuário digitou em /novameta.

function paraObjetoMeta(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    nome: textoDe(p["Nome"]),
    orcamento_total: (p["Orçamento Total"] && p["Orçamento Total"].number) || 0,
    valor_acumulado: (p["Valor Acumulado"] && p["Valor Acumulado"].number) || 0,
    prazo: textoDe(p["Prazo"]),
    status: (p["Status"] && p["Status"].select && p["Status"].select.name) || "",
    criado_em: (p["Criado Em"] && p["Criado Em"].date && p["Criado Em"].date.start) || "",
  };
}

function propsDeMeta(m) {
  const criadoEm = paraIso(m.criado_em) || new Date().toISOString().slice(0, 10);
  return {
    "Nome": { title: richText(m.nome || "(sem nome)") },
    "Orçamento Total": { number: Number(m.orcamento_total) || 0 },
    "Valor Acumulado": { number: Number(m.valor_acumulado) || 0 },
    "Prazo": { rich_text: richText(m.prazo) },
    "Status": selectOrNull(m.status),
    "Criado Em": { date: { start: criadoEm } },
  };
}

/** Update parcial: só o cache de progresso (nunca fonte da verdade — ver metas.js). */
function propsValorAcumulado(valor) {
  return { "Valor Acumulado": { number: Number(valor) || 0 } };
}

/** Update parcial: só o Status (ex.: encerrar uma meta). */
function propsStatus(status) {
  return { "Status": selectOrNull(status) };
}

// ─── Contas Fixas ───────────────────────────────────────────────────────────
// Dia Vencimento fica RICH_TEXT (não Number): lembretes.js aceita tanto um dia
// numérico (1–31) quanto o literal "sexta-feira" (contas semanais) — um Number
// do Notion não representaria essa segunda forma.

function paraObjetoContaFixa(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    nome: textoDe(p["Nome"]),
    dia_vencimento: textoDe(p["Dia Vencimento"]),
    valor_esperado: (p["Valor Esperado"] && p["Valor Esperado"].number) || 0,
    // string "sim"/"não": lembretes.js/relatorio.js comparam com essa convenção
    // (normalizar(f.ativo) === "sim"), herdada do Sheets — o checkbox boolean do
    // Notion é traduzido aqui pra não precisar tocar nos dois arquivos compartilhados.
    ativo: (p["Ativo"] && p["Ativo"].checkbox) ? "sim" : "não",
  };
}

function propsDeContaFixa(c) {
  return {
    "Nome": { title: richText(c.nome || "(sem nome)") },
    "Dia Vencimento": { rich_text: richText(c.dia_vencimento) },
    "Valor Esperado": { number: Number(c.valor_esperado) || 0 },
    "Ativo": { checkbox: String(c.ativo).trim().toLowerCase() === "sim" },
  };
}

// ─── Config ─────────────────────────────────────────────────────────────────

function paraObjetoConfig(page) {
  const p = (page && page.properties) || {};
  return { _id: page && page.id, chave: textoDe(p["Chave"]), valor: textoDe(p["Valor"]) };
}

function propsDeConfig(c) {
  return {
    "Chave": { title: richText(c.chave || "(sem chave)") },
    "Valor": { rich_text: richText(c.valor) },
  };
}

// ─── Log ────────────────────────────────────────────────────────────────────

/** Necessário a partir da Fase B: categorizacao-hibrida lê o Log p/ não perguntar 2x. */
function paraObjetoLog(page) {
  const p = (page && page.properties) || {};
  return {
    _id: page && page.id,
    timestamp: (p["Timestamp"] && p["Timestamp"].date && p["Timestamp"].date.start) || "",
    acao: textoDe(p["Ação"]),
    entidade: textoDe(p["Entidade"]),
    valor_anterior: textoDe(p["Valor Anterior"]),
    valor_novo: textoDe(p["Valor Novo"]),
    origem: (p["Origem"] && p["Origem"].select && p["Origem"].select.name) || "",
  };
}

function propsDeLog(l) {
  const registro = `${l.acao || ""} — ${l.entidade || ""}`.trim();
  return {
    "Registro": { title: richText(registro || "log") },
    "Timestamp": { date: { start: l.timestamp || new Date().toISOString() } },
    "Ação": { rich_text: richText(l.acao) },
    "Entidade": { rich_text: richText(l.entidade) },
    "Valor Anterior": { rich_text: richText(l.valor_anterior) },
    "Valor Novo": { rich_text: richText(l.valor_novo) },
    "Origem": selectOrNull(l.origem),
  };
}


// ── Glue: roteia acao (metas | nova-meta | callback) — Notion ──
const e = $('Início').first().json;
const acao = String(e.acao || '');
let inj = null;
try { if (e.estado) inj = JSON.parse(e.estado); } catch (x) {}
const dry = !!inj; // harness: estado injetado → dry-run (retorna decisão, não escreve)
const brutos = dry ? null : $('Ler Dados (Notion)').first().json;
const metas = dry ? (inj.metas || []) : brutos.metasRows.map(paraObjetoMeta);
const lancs = dry ? (inj.lancamentos || []) : brutos.lancamentosComMeta.map(paraObjetoLancamento);
const agora = new Date().toISOString();
const hoje = agora.slice(0, 10);
let saida = [];

if (acao === 'metas') {
  const prog = calcularProgresso(metas, lancs);
  saida.push({ json: { fase: 'listar', texto: montarMensagemMetas(prog), teclado: montarTecladoMetas(prog) } });
  // Cache: reescreve Valor Acumulado de cada meta ativa pelo derivado (patch parcial por page).
  const ativas = metas.filter((m) => String(m.status || '').trim().toLowerCase() === 'ativa');
  const atualizacoes = ativas.map((m) => {
    const p = prog.find((x) => x.nome === String(m.nome || '').trim());
    return { pageId: m._id, valor: p ? p.acumulado : 0 };
  });
  if (atualizacoes.length) saida.push({ json: { fase: 'cache', atualizacoes } });
} else if (acao === 'nova-meta') {
  const r = parsearNovaMeta(e.texto || '');
  if (!r.ok) {
    saida.push({ json: { fase: 'avisar', texto: r.erro } });
  } else if (nomeJaExisteAtiva(r.meta.nome, metas)) {
    saida.push({ json: { fase: 'avisar', texto: '⚠️ Já existe uma meta ativa "' + r.meta.nome + '". Encerre a atual ou escolha outro nome.' } });
  } else {
    const m = r.meta;
    saida.push({ json: { fase: 'criar',
      meta: { nome: m.nome, orcamento_total: m.orcamento, valor_acumulado: 0, prazo: m.prazo, status: 'ativa', criado_em: hoje },
      log: { timestamp: agora, acao: 'meta_criada', entidade: m.nome, valor_anterior: '', valor_novo: 'orçamento ' + m.orcamento + ' · prazo ' + m.prazo, origem: 'gerenciar-metas' },
      texto: '🎯 Meta criada: ' + m.nome + '\n📊 Orçamento ' + formatarReal(m.orcamento) + ' · prazo ' + m.prazo } });
  }
} else if (acao === 'callback') {
  const cb = parsearCallbackMetaGestao(e.data || '');
  if (!cb) {
    saida.push({ json: { fase: 'recusar', aviso: 'Botão inválido ou expirado.' } });
  } else if (cb.acao === 'nova') {
    saida.push({ json: { fase: 'template', texto: TEMPLATE_NOVAMETA } });
  } else {
    const alvo = String(cb.nome || '').trim();
    const metaAlvo = metas.find((m) => String(m.nome || '').trim() === alvo && String(m.status || '').trim().toLowerCase() === 'ativa');
    if (!metaAlvo) {
      saida.push({ json: { fase: 'recusar', aviso: 'Meta não está mais ativa.' } });
    } else if (cb.acao === 'encerrar-confirmar') {
      saida.push({ json: { fase: 'confirmar', nome: alvo, teclado: montarTecladoConfirmarEncerrar(alvo),
