        texto_edit: '🏁 Meta "' + alvo + '" encerrada. Sai da lista; o histórico permanece.' } });
    }
  }
}

const modo = dry ? 'teste' : 'real';
return saida.map((s) => ({ json: { ...s.json, modo } }));

